const p = String(getPathname(url) || "").toLowerCase();
const isApiToken = p === "/api/auth/token";

// Show exchanging banner.

// IMPORTANT:
// When we're on /api/auth/token, we expect it to postMessage AUTH_SUCCESS directly
// from the WebView HTML response. Do NOT also run a native POST exchange here.
// Native token exchange has proven unreliable across WKWebView/TestFlight builds.
if (!isApiToken) {
  // Fire-and-forget (we can't block onLoadEnd).
  exchangeTokenNative(url);
}

